mapper.select:
select lr.id, lr.elder_id, lr.check_in_id, lr.leave_type, lr.start_time, lr.expected_return_time, lr.actual_return_time, lr.leave_days, lr.emergency_contact, lr.emergency_phone, lr.reason, lr.status, lr.approver, lr.approve_time, e.name as elder_name, b.bed_number from leave_record lr left join elder e on lr.elder_id = e.id left join check_in ci on lr.check_in_id = ci.id left join check_in_cost cic on ci.id = cic.check_in_id left join bed b on cic.bed_id = b.id
and e.name like concat('%', #{elderName}, '%') and lr.status = #{status} and lr.leave_type = #{leaveType}
order by lr.create_time desc

mapper.update:
update leave_record
elder_id = #{elderId}, check_in_id = #{checkInId}, leave_type = #{leaveType}, start_time = #{startTime}, expected_return_time = #{expectedReturnTime}, actual_return_time = #{actualReturnTime}, leave_days = #{leaveDays}, emergency_contact = #{emergencyContact}, emergency_phone = #{emergencyPhone}, reason = #{reason}, status = #{status}, approver = #{approver}, approve_time = #{approveTime}, remark = #{remark}, update_time = #{updateTime}, update_by = #{updateBy},
where id = #{id}
